// Sumber video avatar Kira di dashboard. Pakai versi .mov sesuai permintaan.
// Catatan: .mov (QuickTime) didukung di Safari/macOS, tapi sebagian browser lain
// (mis. Chrome) bisa gagal render — komponen Avatar punya fallback otomatis ke
// gambar (AVATAR_IMG) lewat onError, jadi tetap aman.
const AVATAR_VIDEO = "/avatar.mov";

// Avatar Kira. Default = gambar statis AVATAR_IMG (ringan, dipakai di bubble chat,
// sidebar, header — biar tidak lag karena dirender berulang). Untuk dashboard /
// hero, lewatkan prop `video` agar render <video> bergerak; ada poster + fallback
// otomatis ke gambar bila video gagal dimuat / format tidak didukung.
function Avatar({ style, alt = "Kira", className, video = false }) {
  const [videoFailed, setVideoFailed] = useState(false);
  if (video && AVATAR_VIDEO && !videoFailed) {
    return (
      <video
        src={AVATAR_VIDEO}
        className={className}
        style={{ ...style, objectFit: "cover" }}
        poster={AVATAR_IMG}
        autoPlay
        loop
        muted
        playsInline
        aria-label={alt}
        onError={() => setVideoFailed(true)}
      />
    );
  }
  return <img src={AVATAR_IMG} alt={alt} className={className} style={style} />;
}

// VoiceWave: overlay spektrum audio ala Jarvis saat Kira bicara. Menggambar
// bar simetris di canvas dengan animasi gelombang sintetis yang halus. Hanya
// tampil saat Kira benar-benar bersuara (subscribe ke speechPlaying). Sengaja
// TIDAK menyentuh audio asli supaya suara Kira tidak pernah terganggu.
function VoiceWave() {
  const [active, setActive] = React.useState(speechPlaying);
  const canvasRef = useRef(null);

  // Subscribe ke sinyal "Kira sedang bersuara".
  useEffect(() => {
    const fn = (v) => setActive(v);
    speechListeners.add(fn);
    setActive(speechPlaying);
    return () => { speechListeners.delete(fn); };
  }, []);

  // Loop gambar selama aktif.
  useEffect(() => {
    if (!active) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    let raf = 0, t = 0;

    const resize = () => {
      const dpr = window.devicePixelRatio || 1;
      const w = canvas.clientWidth, h = canvas.clientHeight;
      canvas.width = Math.max(1, Math.floor(w * dpr));
      canvas.height = Math.max(1, Math.floor(h * dpr));
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    };
    resize();
    window.addEventListener("resize", resize);

    const BARS = 48;
    const draw = () => {
      const w = canvas.clientWidth, h = canvas.clientHeight;
      ctx.clearRect(0, 0, w, h);
      const mid = h / 2;
      const gap = 2;
      const barW = (w - gap * (BARS - 1)) / BARS;

      // Amplitudo per-bar: animasi gelombang sintetis (beberapa sinus ditumpuk)
      // supaya terlihat organik & "hidup". Sengaja TIDAK membaca audio asli —
      // visualizer murni dekoratif, tidak boleh mengganggu suara/alur Kira.
      const amps = new Array(BARS);
      for (let i = 0; i < BARS; i++) {
        const p = i / BARS;
        const env = Math.sin(p * Math.PI); // lebih tinggi di tengah
        const wsum =
          0.5 * Math.sin(t * 0.18 + p * 7) +
          0.3 * Math.sin(t * 0.27 + p * 13 + 1.5) +
          0.2 * Math.sin(t * 0.4 + p * 3);
        amps[i] = Math.max(0.05, env * (0.45 + 0.4 * (wsum * 0.5 + 0.5)));
      }

      for (let i = 0; i < BARS; i++) {
        const x = i * (barW + gap);
        const bh = Math.max(2, amps[i] * (h * 0.92));
        const grad = ctx.createLinearGradient(0, mid - bh / 2, 0, mid + bh / 2);
        grad.addColorStop(0, "#E05454");
        grad.addColorStop(0.5, "#C13383");
        grad.addColorStop(1, "#792CA2");
        ctx.fillStyle = grad;
        const r = Math.min(barW / 2, 3);
        const yTop = mid - bh / 2;
        // Bar membulat (simetris atas-bawah dari tengah).
        ctx.beginPath();
        ctx.roundRect ? ctx.roundRect(x, yTop, barW, bh, r) : ctx.rect(x, yTop, barW, bh);
        ctx.fill();
      }

      t += 1;
      raf = requestAnimationFrame(draw);
    };
    raf = requestAnimationFrame(draw);

    return () => { cancelAnimationFrame(raf); window.removeEventListener("resize", resize); };
  }, [active]);

  if (!active) return null;
  return (
    <div className="kira-wave-overlay" aria-hidden="true">
      <div className="kira-wave-card">
        <div className="kira-wave-orb"><span /></div>
        <canvas ref={canvasRef} className="kira-wave-canvas" />
        <div className="kira-wave-label">Kira lagi ngomong…</div>
      </div>
    </div>
  );
}

// VoiceGlow: lapisan background gradien yang berdenyut/kedap-kedip secara
// organik di belakang room chat selama Kira bicara. Dipicu sinyal speechPlaying
// yang sama (murni animasi CSS, TIDAK menyentuh audio). Memberi kesan ruangan
// "bereaksi" ke suara Kira tanpa risiko membisukan/menghang.
function VoiceGlow() {
  const [active, setActive] = React.useState(speechPlaying);
  useEffect(() => {
    const fn = (v) => setActive(v);
    speechListeners.add(fn);
    setActive(speechPlaying);
    return () => { speechListeners.delete(fn); };
  }, []);
  return <div className={"kira-room-glow" + (active ? " on" : "")} aria-hidden="true" />;
}


