// Unduh teks sebagai file (dipakai untuk export konten Kira ke .md).
function downloadText(filename, text) {
  const blob = new Blob([text], { type: "text/plain;charset=utf-8" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  setTimeout(() => URL.revokeObjectURL(url), 1000);
}

// --- Voice command (Web Speech API) ---------------------------------------
// Pakai SpeechRecognition (dengar) + speechSynthesis (bicara) bawaan browser.
// Gratis, tanpa dependency. Bahasa Indonesia (id-ID).

// Apakah browser mendukung speech recognition?
const SpeechRecognitionCls =
  typeof window !== "undefined" ? (window.SpeechRecognition || window.webkitSpeechRecognition) : null;
const voiceSupported = !!SpeechRecognitionCls && typeof window !== "undefined" && !!window.speechSynthesis;

// Wake word: "halo kira", "hai kira", "hey kira", dst.
const WAKE_RE = /\b(halo|hallo|hai|hi|hey|oke|ok)\s*,?\s*kira\b/i;
const matchWake = (t) => WAKE_RE.test(t || "");
// Buang bagian wake word dari transkrip kalau perintah menyusul di kalimat sama.
