// Ambil alternatif transkrip dengan confidence tertinggi dari satu hasil
// recognition. Recognizer kadang menaruh tebakan yang lebih tepat di alternatif
// ke-2/3, jadi memilih yang paling pede mengurangi salah dengar.
function bestAlternative(res) {
  if (!res || !res.length) return "";
  let best = res[0];
  for (let i = 1; i < res.length; i++) {
    if ((res[i]?.confidence || 0) > (best?.confidence || 0)) best = res[i];
  }
  return (best?.transcript || res[0]?.transcript || "").trim();
}

// Audio element + AbortController aktif untuk TTS ElevenLabs. Dipakai supaya
// ucapan sebelumnya bisa dihentikan sebelum yang baru diputar.
let currentAudio = null;
let currentTtsAbort = null;

// --- Sinyal "Kira sedang bicara" untuk visualizer -------------------------
// PENTING (pelajaran dari beberapa percobaan): visualizer TIDAK BOLEH menyentuh
// audio sama sekali. createMediaElementSource maupun captureStream + Web Audio
// terbukti bisa membuat suara Kira bisu / membekukan alur. Maka wave digambar
// MURNI sebagai animasi sintetis yang hanya dipicu sinyal di bawah. Audio
// diputar apa adanya, tanpa node Web Audio apa pun.
let speechPlaying = false;
const speechListeners = new Set();
function setSpeechPlaying(v) {
  if (speechPlaying === v) return;
  speechPlaying = v;
  speechListeners.forEach((fn) => { try { fn(v); } catch { /* ignore */ } });
}

// Hentikan semua ucapan yang sedang berjalan (browser TTS + ElevenLabs audio).
function cancelSpeech() {
  try { window.speechSynthesis?.cancel(); } catch { /* ignore */ }
  if (currentTtsAbort) { try { currentTtsAbort.abort(); } catch { /* ignore */ } currentTtsAbort = null; }
  if (currentAudio) {
    try { currentAudio.pause(); currentAudio.src = ""; } catch { /* ignore */ }
    currentAudio = null;
  }
  setSpeechPlaying(false);
}

// Fallback: ucapkan teks pakai speechSynthesis bawaan browser (dipakai kalau
// ElevenLabs gagal / belum dikonfigurasi). onend dipanggil saat selesai.
function speakBrowser(text, { onend } = {}) {
  if (typeof window === "undefined" || !window.speechSynthesis) { onend?.(); return; }
  try {
    window.speechSynthesis.cancel();
    const u = new SpeechSynthesisUtterance(text);
    u.lang = "id-ID";
    u.rate = 1.05;
    u.pitch = 1.1;
    const voices = window.speechSynthesis.getVoices();
    const id = voices.find((v) => /id[-_]ID/i.test(v.lang)) || voices.find((v) => /indonesi/i.test(v.name));
    if (id) u.voice = id;
    const finish = () => { setSpeechPlaying(false); onend?.(); };
    u.onstart = () => { setSpeechPlaying(true); };
    u.onend = finish;
    u.onerror = finish;
    window.speechSynthesis.speak(u);
  } catch {
    setSpeechPlaying(false);
    onend?.();
  }
}

// Ucapkan teks. Utamakan ElevenLabs (lewat backend /api/tts) untuk suara yang
// natural & human; kalau gagal (offline, kuota habis, belum dikonfigurasi),
// otomatis fallback ke suara browser. onend selalu dipanggil sekali saat selesai
// (atau saat gagal) supaya alur voice command tetap lanjut.
function speak(text, { onend } = {}) {
  if (typeof window === "undefined" || !text) { onend?.(); return; }
  cancelSpeech(); // hentikan ucapan sebelumnya

  // SAFETY NET: onend WAJIB terpanggil tepat sekali, apa pun yang terjadi.
  // Kalau audio macet (stalled, tidak pernah 'ended', dsb), watchdog memaksa
  // selesai supaya voiceStatus tidak nyangkut di "speaking"/"thinking" — itu
  // yang bikin Kira jadi tuli & input berikutnya tidak bisa.
  let finished = false;
  const est = Math.min(20000, Math.max(4000, (text.length || 20) * 120));
  let watchdog = setTimeout(() => finishOnce(), est);
  const finishOnce = () => {
    if (finished) return;
    finished = true;
    clearTimeout(watchdog);
    setSpeechPlaying(false);
    onend?.();
  };

  const controller = new AbortController();
  currentTtsAbort = controller;

  fetch("/api/tts", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ text }),
    signal: controller.signal,
  })
    .then(async (res) => {
      if (!res.ok) throw new Error("tts unavailable");
      const blob = await res.blob();
      // Kalau request ini sudah dibatalkan oleh ucapan baru, jangan putar.
      if (currentTtsAbort !== controller) return;
      const url = URL.createObjectURL(blob);
      const audio = new Audio(url);
      currentAudio = audio;
      const done = () => {
        URL.revokeObjectURL(url);
        if (currentAudio === audio) currentAudio = null;
        if (currentTtsAbort === controller) currentTtsAbort = null;
        finishOnce();
      };
      // Wave nyala saat audio benar-benar berbunyi, mati saat selesai.
      audio.onplaying = () => {
        setSpeechPlaying(true);
        // Audio mulai jalan: perpanjang watchdog ke durasi nyata + buffer.
        clearTimeout(watchdog);
        const dur = isFinite(audio.duration) && audio.duration > 0 ? audio.duration * 1000 : est;
        watchdog = setTimeout(() => done(), dur + 3000);
      };
      audio.onended = done;
      audio.onerror = done;
      audio.play().catch(() => done());
    })
    .catch((err) => {
      // AbortError = sengaja dihentikan ucapan baru; jangan fallback/onend ganda.
      if (err?.name === "AbortError") { finished = true; clearTimeout(watchdog); return; }
      if (currentTtsAbort === controller) currentTtsAbort = null;
      // ElevenLabs gagal -> pakai suara browser. Bungkus onend agar watchdog ikut bersih.
      speakBrowser(text, { onend: finishOnce });
    });
}


// --- Auth helpers (klien) --------------------------------------------------
// Token login disimpan di localStorage. Semua request auth/sesi menyertakan
// header Authorization. Kalau user belum login, app tetap jalan pakai
// localStorage seperti biasa (mode tamu) — tanpa regresi.
const TOKEN_KEY = "kira_auth_token";
const getToken = () => { try { return localStorage.getItem(TOKEN_KEY) || null; } catch { return null; } };
const setToken = (t) => { try { t ? localStorage.setItem(TOKEN_KEY, t) : localStorage.removeItem(TOKEN_KEY); } catch { /* ignore */ } };

// Wrapper fetch untuk endpoint API: otomatis sisipkan token + JSON header.
async function apiFetch(path, { method = "GET", body } = {}) {
  const headers = { "Content-Type": "application/json" };
  const token = getToken();
  if (token) headers.Authorization = `Bearer ${token}`;
  const res = await fetch(path, { method, headers, ...(body ? { body: JSON.stringify(body) } : {}) });
  let data = null;
  try { data = await res.json(); } catch { /* respons tanpa JSON */ }
  if (!res.ok) throw new Error(data?.error || `Request gagal (${res.status})`);
  return data;
}

const authApi = {
  register: (email, password, name) => apiFetch("/api/auth/register", { method: "POST", body: { email, password, name } }),
  login: (email, password) => apiFetch("/api/auth/login", { method: "POST", body: { email, password } }),
  logout: () => apiFetch("/api/auth/logout", { method: "POST" }),
  me: () => apiFetch("/api/auth/me"),
};

const sessionsApi = {
  list: () => apiFetch("/api/sessions"),
  get: (id) => apiFetch(`/api/sessions/${id}`),
  save: (id, title, messages) => apiFetch(`/api/sessions/${encodeURIComponent(id)}`, { method: "PUT", body: { title, messages } }),
  remove: (id) => apiFetch(`/api/sessions/${encodeURIComponent(id)}`, { method: "DELETE" }),
};


