// Modal login/register. Hemat: satu form, mode toggle. Sukses -> onSuccess({token,user}).
function AuthModal({ onClose, onSuccess }) {
  const [mode, setMode] = useState("login"); // "login" | "register"
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [name, setName] = useState("");
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState("");

  const submit = async () => {
    setError("");
    if (!email.trim() || !password) { setError("Email & password wajib diisi."); return; }
    if (mode === "register" && password.length < 8) { setError("Password minimal 8 karakter."); return; }
    setBusy(true);
    try {
      const data = mode === "login"
        ? await authApi.login(email.trim(), password)
        : await authApi.register(email.trim(), password, name.trim());
      await onSuccess(data);
    } catch (e) {
      setError(e.message || "Gagal, coba lagi ya.");
    } finally {
      setBusy(false);
    }
  };

  const inputStyle = { width: "100%", boxSizing: "border-box", padding: "11px 13px", borderRadius: 11, border: "1px solid #E2E2E8", background: "#FAFAFA", fontSize: 14, fontFamily: "'DM Sans', sans-serif", color: "#333", marginTop: 8 };

  return (
    <div onClick={onClose} style={{ position: "fixed", inset: 0, background: "rgba(20,12,30,0.55)", zIndex: 70, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
      <div onClick={e => e.stopPropagation()} className="kira-auth" style={{ background: "#fff", borderRadius: 20, width: "100%", maxWidth: 400, padding: 26, boxShadow: "0 24px 60px -12px rgba(68,49,153,0.4)" }}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 4 }}>
          <h2 style={{ fontFamily: "'Plus Jakarta Sans', sans-serif", fontWeight: 800, fontSize: 20, margin: 0 }}>
            <span style={gradText}>{mode === "login" ? "Masuk" : "Daftar"}</span>
          </h2>
          <button onClick={onClose} title="Tutup" style={{ background: "transparent", border: "none", cursor: "pointer", color: "#999", display: "flex" }}><X size={20} /></button>
        </div>
        <p style={{ fontSize: 13, color: "#888", marginTop: 0, lineHeight: 1.5 }}>
          Simpan riwayat chat biar nggak hilang walau ganti browser, bestie.
        </p>

        {mode === "register" && (
          <input value={name} onChange={e => setName(e.target.value)} placeholder="Nama (opsional)" style={inputStyle} />
        )}
        <input value={email} onChange={e => setEmail(e.target.value)} type="email" placeholder="Email" autoComplete="email" style={inputStyle} />
        <input value={password} onChange={e => setPassword(e.target.value)} type="password" placeholder="Password (min 8 karakter)" autoComplete={mode === "login" ? "current-password" : "new-password"}
          onKeyDown={e => { if (e.key === "Enter") submit(); }} style={inputStyle} />

        {error && <div style={{ fontSize: 12.5, color: "#E05454", marginTop: 10 }}>{error}</div>}

        <button onClick={submit} disabled={busy} style={{
          ...ctaBtn, justifyContent: "center", width: "100%", marginTop: 16, padding: "12px", opacity: busy ? 0.6 : 1, cursor: busy ? "not-allowed" : "pointer",
        }}>
          {busy ? "Sebentar ya…" : (mode === "login" ? "Masuk" : "Daftar")}
        </button>

        <div style={{ textAlign: "center", fontSize: 13, color: "#888", marginTop: 14 }}>
          {mode === "login" ? "Belum punya akun? " : "Sudah punya akun? "}
          <button onClick={() => { setMode(mode === "login" ? "register" : "login"); setError(""); }}
            style={{ background: "transparent", border: "none", cursor: "pointer", color: "#792CA2", fontWeight: 700, fontSize: 13 }}>
            {mode === "login" ? "Daftar" : "Masuk"}
          </button>
        </div>
      </div>
    </div>
  );
}



