// Generator jadwal posting client-side (tanpa panggilan Gemini, jadi instan &
// gratis). Persona Kira menyarankan "post 3x sehari per produk" — komponen ini
// mewujudkannya jadi tabel mingguan: tiap produk dapat 3 slot prime-time/hari
// dengan angle yang dirotasi biar variatif. Bisa di-export ke CSV.
function ContentCalendar({ onClose, products }) {
  const [days, setDays] = useState(7);
  // Produk: pakai judul sesi (otomatis dari produk yang dibahas). Kalau kosong,
  // sediakan placeholder agar tabel tetap berguna.
  const productList = products.length ? [...new Set(products)] : ["Produk 1"];

  const dayNames = ["Senin", "Selasa", "Rabu", "Kamis", "Jumat", "Sabtu", "Minggu"];
  const today = new Date();

  // Bangun baris jadwal: untuk tiap hari × tiap slot prime-time, rotasi produk
  // & angle supaya tidak monoton.
  const rows = [];
  let counter = 0;
  for (let d = 0; d < days; d++) {
    const date = new Date(today);
    date.setDate(today.getDate() + d);
    const tanggal = `${String(date.getDate()).padStart(2, "0")}/${String(date.getMonth() + 1).padStart(2, "0")}`;
    PRIME_TIME_SLOTS.forEach((jam) => {
      const produk = productList[counter % productList.length];
      const angle = CONTENT_ANGLES[counter % CONTENT_ANGLES.length];
      rows.push({ hari: dayNames[date.getDay() === 0 ? 6 : date.getDay() - 1], tanggal, jam, produk, angle });
      counter++;
    });
  }

  const exportCsv = () => {
    const header = ["Hari", "Tanggal", "Jam", "Produk", "Angle Konten"];
    const lines = [header, ...rows.map(r => [r.hari, r.tanggal, r.jam, r.produk, r.angle])];
    // Escape tiap sel: bungkus quote & gandakan quote di dalam (format CSV standar).
    const csv = lines.map(cols => cols.map(c => `"${String(c).replace(/"/g, '""')}"`).join(",")).join("\n");
    downloadText(`kira-content-calendar-${days}hari.csv`, "\uFEFF" + csv);
  };
  return (
    <div onClick={onClose} style={{ position: "fixed", inset: 0, background: "rgba(20,12,30,0.55)", zIndex: 60, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
      <div onClick={e => e.stopPropagation()} className="kira-cal" style={{ background: "#fff", borderRadius: 20, width: "100%", maxWidth: 720, maxHeight: "85vh", display: "flex", flexDirection: "column", overflow: "hidden", boxShadow: "0 24px 60px -12px rgba(68,49,153,0.4)" }}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "18px 22px", borderBottom: "1px solid #EEE" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <CalendarDays size={20} color="#792CA2" />
            <div>
              <div style={{ fontFamily: "'Plus Jakarta Sans', sans-serif", fontWeight: 800, fontSize: 17 }}>Content Calendar</div>
              <div style={{ fontSize: 12, color: "#888" }}>Jadwal posting 3x/hari di jam prime-time</div>
            </div>
          </div>
          <button onClick={onClose} title="Tutup" style={{ background: "transparent", border: "none", cursor: "pointer", color: "#999", display: "flex" }}><X size={20} /></button>
        </div>

        <div style={{ display: "flex", alignItems: "center", gap: 10, padding: "14px 22px", borderBottom: "1px solid #F3F0F8", flexWrap: "wrap" }}>
          <span style={{ fontSize: 13, fontWeight: 600, color: "#555" }}>Durasi:</span>
          {[3, 7, 14].map(n => (
            <button key={n} onClick={() => setDays(n)} style={{
              fontSize: 12.5, fontWeight: 600, padding: "6px 14px", borderRadius: 100, cursor: "pointer",
              border: days === n ? "none" : "1px solid #E2E2E8",
              background: days === n ? "linear-gradient(135deg,#E05454,#792CA2)" : "#fff",
              color: days === n ? "#fff" : "#666",
            }}>{n} hari</button>
          ))}
          <button onClick={exportCsv} style={{ marginLeft: "auto", display: "flex", alignItems: "center", gap: 6, fontSize: 12.5, fontWeight: 700, padding: "8px 14px", borderRadius: 10, cursor: "pointer", border: "1px solid #E2D9F0", background: "#fff", color: "#792CA2" }}>
            <Download size={14} /> Export CSV
          </button>
        </div>

        <div style={{ overflowY: "auto", padding: "8px 22px 22px" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 13.5 }}>
            <thead>
              <tr style={{ textAlign: "left", color: "#888", fontSize: 11, textTransform: "uppercase", letterSpacing: "0.05em" }}>
                <th style={{ padding: "10px 8px", position: "sticky", top: 0, background: "#fff" }}>Hari</th>
                <th style={{ padding: "10px 8px", position: "sticky", top: 0, background: "#fff" }}>Jam</th>
                <th style={{ padding: "10px 8px", position: "sticky", top: 0, background: "#fff" }}>Produk</th>
                <th style={{ padding: "10px 8px", position: "sticky", top: 0, background: "#fff" }}>Angle</th>
              </tr>
            </thead>
            <tbody>
              {rows.map((r, i) => (
                <tr key={i} style={{ borderTop: "1px solid #F3F0F8" }}>
                  <td style={{ padding: "10px 8px", whiteSpace: "nowrap" }}><span style={{ fontWeight: 600 }}>{r.hari}</span> <span style={{ color: "#AAA" }}>{r.tanggal}</span></td>
                  <td style={{ padding: "10px 8px", whiteSpace: "nowrap", color: "#792CA2", fontWeight: 600 }}>{r.jam}</td>
                  <td style={{ padding: "10px 8px" }}>{r.produk}</td>
                  <td style={{ padding: "10px 8px", color: "#5B5B66" }}>{r.angle}</td>
                </tr>
              ))}
            </tbody>
          </table>
          <div style={{ fontSize: 11.5, color: "#AAA", marginTop: 14, lineHeight: 1.5 }}>
            Produk diambil otomatis dari chat yang sudah kamu buat. Jam prime-time bersifat perkiraan umum untuk audiens Indonesia — sesuaikan dengan analitik akunmu sendiri ya bestie.
          </div>
        </div>
      </div>
    </div>
  );
}






