// Kartu dengan animasi: muncul 3D saat discroll masuk viewport
// (IntersectionObserver) + miring mengikuti kursor (tilt 3D) saat di-hover.
// Transform tilt ditulis ke CSS variable supaya halus tanpa re-render.
function TiltCard({ children, cardStyle }) {
  const ref = useRef(null);
  const rafRef = useRef(0);
  const [shown, setShown] = useState(false);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const io = new IntersectionObserver((entries) => {
      entries.forEach((e) => {
        if (e.isIntersecting) { setShown(true); io.unobserve(e.target); }
      });
    }, { threshold: 0.18 });
    io.observe(el);
    return () => io.disconnect();
  }, []);

  const onMove = (e) => {
    const el = ref.current;
    if (!el) return;
    const r = el.getBoundingClientRect();
    const px = (e.clientX - r.left) / r.width - 0.5;
    const py = (e.clientY - r.top) / r.height - 0.5;
    cancelAnimationFrame(rafRef.current);
    rafRef.current = requestAnimationFrame(() => {
      el.style.setProperty("--rx", (py * -9).toFixed(2) + "deg");
      el.style.setProperty("--ry", (px * 11).toFixed(2) + "deg");
      el.style.setProperty("--gx", ((px + 0.5) * 100).toFixed(1) + "%");
      el.style.setProperty("--gy", ((py + 0.5) * 100).toFixed(1) + "%");
    });
  };
  const onLeave = () => {
    const el = ref.current;
    if (!el) return;
    cancelAnimationFrame(rafRef.current);
    el.style.setProperty("--rx", "0deg");
    el.style.setProperty("--ry", "0deg");
  };

  return (
    <div ref={ref} className={"kira-tilt" + (shown ? " in-view" : "")} onMouseMove={onMove} onMouseLeave={onLeave}>
      <div className="kira-card-inner" style={cardStyle}>
        <span className="kira-card-sheen" aria-hidden="true" />
        {children}
      </div>
    </div>
  );
}

